// Stages the MediaPipe WASM runtime and hand-landmark model locally under
// public/ so the app runs fully offline at runtime — no CDN fetch, no cloud
// AI service calls. These are binary assets (~40MB total); they're
// regenerated by this script rather than committed to git.
//
// Usage: node scripts/setup-mediapipe-assets.mjs

import { existsSync, mkdirSync, copyFileSync, readdirSync, writeFileSync } from 'node:fs'
import { dirname, join } from 'node:path'
import { fileURLToPath } from 'node:url'

const ROOT = dirname(dirname(fileURLToPath(import.meta.url)))

const WASM_SRC = join(ROOT, 'node_modules/@mediapipe/tasks-vision/wasm')
const WASM_DEST = join(ROOT, 'public/mediapipe/wasm')

const MODEL_URL =
  'https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/1/hand_landmarker.task'
const MODEL_DEST_DIR = join(ROOT, 'public/models')
const MODEL_DEST = join(MODEL_DEST_DIR, 'hand_landmarker.task')

function copyWasmRuntime() {
  if (!existsSync(WASM_SRC)) {
    throw new Error(`MediaPipe wasm source not found at ${WASM_SRC}. Run "npm install" first.`)
  }
  mkdirSync(WASM_DEST, { recursive: true })
  for (const file of readdirSync(WASM_SRC)) {
    copyFileSync(join(WASM_SRC, file), join(WASM_DEST, file))
  }
  console.log(`Copied MediaPipe wasm runtime -> ${WASM_DEST}`)
}

async function downloadModel() {
  if (existsSync(MODEL_DEST)) {
    console.log(`Model already present at ${MODEL_DEST}, skipping download.`)
    return
  }
  mkdirSync(MODEL_DEST_DIR, { recursive: true })
  console.log(`Downloading hand_landmarker.task from ${MODEL_URL} ...`)
  const response = await fetch(MODEL_URL)
  if (!response.ok) {
    throw new Error(`Failed to download model: ${response.status} ${response.statusText}`)
  }
  const bytes = new Uint8Array(await response.arrayBuffer())
  writeFileSync(MODEL_DEST, bytes)
  console.log(`Saved model -> ${MODEL_DEST}`)
}

copyWasmRuntime()
await downloadModel()
